<template><AdminTablePage title="系统日志" desc="查看登录日志、操作日志与异常日志，辅助系统审计" :list="list" :total="total" :loading="loading" :query="query" :show-add="false" @load="load" :action-width="0"><template #toolbar><el-select v-model="query.logType" clearable placeholder="日志类型" style="width:140px"><el-option label="登录" value="LOGIN"/><el-option label="操作" value="OPERATION"/><el-option label="异常" value="ERROR"/></el-select><el-button type="primary" @click="reload">查询</el-button></template><template #columns><el-table-column prop="logType" label="类型" width="100"/><el-table-column prop="userType" label="用户类型" width="110"/><el-table-column prop="userName" label="用户" width="120"/><el-table-column prop="module" label="模块" width="120"/><el-table-column prop="operation" label="操作" min-width="180"/><el-table-column label="状态" width="90"><template #default="{row}"><el-tag :type="row.status===1?'success':'danger'">{{row.status===1?'成功':'失败'}}</el-tag></template></el-table-column><el-table-column prop="createTime" label="时间" width="180"/></template></AdminTablePage></template><script setup>import{reactive,ref,onMounted}from'vue';import AdminTablePage from '@/components/AdminTablePage.vue';import{adminApi}from'@/api';const query=reactive({pageNum:1,pageSize:10,logType:''});const list=ref([]),total=ref(0),loading=ref(false);const load=async()=>{loading.value=true;try{const p={...query};if(!p.logType)delete p.logType;const r=await adminApi.logs(p);list.value=r.data.records;total.value=Number(r.data.total)}finally{loading.value=false}};const reload=()=>{query.pageNum=1;load()};onMounted(load)</script>